local prompt_matrix = Effect.GlobalEffect()
prompt_matrix:SetType(EFFECT_TYPE_FIELD + EFFECT_TYPE_CONTINUOUS)
prompt_matrix:SetCode(EVENT_STARTUP)
prompt_matrix:SetOperation(function()
  local setup_cards = Duel.GetFieldGroup(0, LOCATION_DECK, 0)
  local first = setup_cards:GetFirst()
  local second = setup_cards:GetNext()

  Duel.MoveToField(first, 0, 0, LOCATION_MZONE, POS_FACEUP_ATTACK, true)
  Duel.MoveToField(second, 0, 0, LOCATION_MZONE, POS_FACEUP_ATTACK, true)
  first:EnableCounterPermit(0x1, LOCATION_MZONE)
  second:EnableCounterPermit(0x1, LOCATION_MZONE)
  first:AddCounter(0x1, 1)
  second:AddCounter(0x1, 1)
  Duel.RemoveCounter(0, 1, 0, 0x1, 2, REASON_EFFECT)

  local deck = Duel.GetFieldGroup(0, LOCATION_DECK, 0)
  local card = deck:GetFirst()
  Duel.SelectYesNo(0, 30)
  Duel.SelectEffectYesNo(0, card, 95)
  Duel.SelectOption(0, true, 70, 71)
  deck:SelectWithSumEqual(0, function() return 1 end, 2, 2, 2)
  deck:SelectUnselect(nil, 0, true, false, 1, 1)
  Duel.SelectDisableField(0, 1, LOCATION_MZONE, 0, 0)
  Duel.SelectPosition(0, card, POS_FACEUP_ATTACK + POS_FACEUP_DEFENSE)
  Duel.SortDecktop(0, 0, 3)
  Duel.AnnounceNumber(0, 1, 2, 3)
  Duel.AnnounceAttribute(0, 1, ATTRIBUTE_LIGHT + ATTRIBUTE_DARK)
  Duel.AnnounceRace(0, 1, RACE_WARRIOR + RACE_SPELLCASTER)
  Duel.AnnounceCard(0, TYPE_MONSTER)
  Duel.RockPaperScissors(false)
  Duel.Win(0, 1)
end)
Duel.RegisterEffect(prompt_matrix, 0)
